// Text responde com o tamanho exato que precisa para o texto:
Text("Olá")  // responde: 28 × 20 pts

// Color é "gulosa" — quer todo o espaço disponível:
Color.blue  // responde: todo o tamanho proposto

// Spacer também é guloso dentro de Stacks:
HStack {
    Text("Esquerda")
    Spacer()  // expande para preencher o restante
    Text("Direita")
}

// HStack com alinhamento e spacing customizado:
HStack(alignment: .top, spacing: 16) {
    Image(systemName: "bell")
    VStack(alignment: .leading, spacing: 4) {
        Text("Notificação").font(.headline)
        Text("Detalhes aqui").font(.caption)
    }
    Spacer()
}

// Alinhamentos comuns de VStack:
VStack(alignment: .leading) { ... }  // alinha filhas à esquerda
VStack(alignment: .center) { ... }  // padrão
VStack(alignment: .trailing) { ... } // alinha à direita

// spacing: 0 para remover espaço entre elementos:
VStack(spacing: 0) {
    DivisorTopo()
    ConteudoPrincipal()
    DivisorBase()
}

// Badge sobre ícone:
ZStack(alignment: .topTrailing) {
    Image(systemName: "bell")
        .font(.title)

    // Badge no canto superior direito:
    Circle()
        .fill(.red)
        .frame(width: 12, height: 12)
        .overlay {
            Text("3")
                .font(.system(size: 8))
                .foregroundStyle(.white)
        }
}

// Overlay de loading sobre conteúdo:
ZStack {
    ConteudoPrincipal()
    if carregando {
        Color.black.opacity(0.4)
        ProgressView()
            .tint(.white)
    }
}

// Empurrar botão para a base:
VStack {
    ConteudoPrincipal()
    Spacer()  // empurra o botão para baixo
    Button("Confirmar") { confirmar() }
        .buttonStyle(.borderedProminent)
}

// Centralizar com espaço igual nos dois lados:
HStack {
    Spacer()
    Text("Centralizado")
    Spacer()
}

// Spacer com mínimo:
HStack {
    Text("Usuário")
    Spacer(minLength: 20)  // pelo menos 20 pts de separação
    Text("Status")
}

// Tamanho fixo:
Image("avatar")
    .frame(width: 60, height: 60)

// Largura máxima — ocupa toda a largura disponível:
Button("Salvar") { salvar() }
    .frame(maxWidth: .infinity)
    .padding()
    .background(.blue)

// Limites mínimos e máximos:
Text(descricao)
    .frame(minHeight: 40, maxHeight: 200)  // cresce mas tem limites

// Alinhamento dentro do frame:
Text("Início")
    .frame(maxWidth: .infinity, alignment: .leading)  // alinha o texto à esquerda

// GeometryReader fora de overlay — ocupa tudo e afeta o layout:
GeometryReader { proxy in
    Text("Largura: \(proxy.size.width)")
}

// Melhor — GeometryReader dentro de overlay para não afetar o layout:
struct BarraDeProgressoView: View {
    let progresso: Double  // 0.0 a 1.0

    var body: some View {
        Rectangle()
            .fill(.secondary.opacity(0.2))
            .frame(height: 8)
            .overlay(alignment: .leading) {
                GeometryReader { proxy in
                    Rectangle()
                        .fill(.blue)
                        .frame(width: proxy.size.width * progresso)
                }
            }
            .clipShape(Capsule())
    }
}

// Leitura do tamanho com preference key (sem afetar layout):
struct MedidorDeAltura: View {
    var body: some View {
        Color.clear
            .frame(height: 0)
            .onGeometryChange(for: CGFloat.self) { proxy in
                proxy.size.height  // iOS 17+
            } action: { novaAltura in
                print("Altura disponível: \(novaAltura)")
            }
    }
}

// VStack normal — cria todos os 1000 itens de uma vez:
ScrollView {
    VStack {  // evite com muitos itens
        ForEach(0..<1000) { i in
            ItemView(numero: i)
        }
    }
}

// LazyVStack — cria apenas o visível:
ScrollView {
    LazyVStack(spacing: 8) {  // use com listas longas
        ForEach(itens) { item in
            ItemView(item: item)
        }
    }
    .padding()
}

// Seções com cabeçalho fixo (pinnedViews):
ScrollView {
    LazyVStack(spacing: 0, pinnedViews: .sectionHeaders) {
        ForEach(secoes) { secao in
            Section {
                ForEach(secao.itens) { item in
                    ItemView(item: item)
                }
            } header: {
                CabecalhoSecao(titulo: secao.titulo)  // fica fixo no scroll
            }
        }
    }
}

// Grid tabular — colunas alinhadas:
Grid(alignment: .leading, horizontalSpacing: 16, verticalSpacing: 8) {
    GridRow {
        Text("Nome").bold()
        Text("Status").bold()
        Text("Data").bold()
    }
    Divider()
        .gridCellUnsizedAxes(.horizontal)
    ForEach(tarefas) { tarefa in
        GridRow {
            Text(tarefa.nome)
            StatusBadge(status: tarefa.status)
            Text(tarefa.data, format: .dateTime.day().month())
        }
    }
}

// LazyVGrid — grid de fotos com colunas adaptativas:
let colunas = [GridItem(.adaptive(minimum: 100))]

ScrollView {
    LazyVGrid(columns: colunas, spacing: 4) {
        ForEach(fotos) { foto in
            FotoView(foto: foto)
                .aspectRatio(1, contentMode: .fill)
        }
    }
}

// Problema: Text quebra linha mesmo com espaço suficiente
HStack(spacing: 0) {
    Color.cyan      // flexibilidade infinita
    Text("Texto")   // menos flexível — recebe espaço dividido
    Color.teal      // flexibilidade infinita
}
// HStack divide 300pts / 3 filhos = 100pts cada
// Text com 100pts pode não ter espaço suficiente!

// Solução 1 — layoutPriority: Text recebe o que precisa primeiro:
HStack(spacing: 0) {
    Color.cyan
    Text("Texto")
        .layoutPriority(1)  // processado antes dos outros
    Color.teal
}

// Solução 2 — fixedSize: Text ignora a proposta, usa tamanho ideal:
HStack(spacing: 0) {
    Color.cyan
    Text("Texto")
        .fixedSize()  // usa tamanho intrínseco, pode sair dos limites
    Color.teal
}

// overlay NÃO afeta o tamanho da View principal:
Text("Olá")
    .padding()
    .overlay(alignment: .topTrailing) {
        Circle()
            .fill(.red)
            .frame(width: 20, height: 20)
        // Circle está SOBRE o Text mas não aumenta o tamanho dele
    }
// Tamanho reportado: tamanho do Text + padding

// ZStack INCLUI todos os filhos no tamanho:
ZStack(alignment: .topTrailing) {
    Text("Olá").padding()
    Circle().fill(.red).frame(width: 20, height: 20)
}
// Tamanho reportado: UNIÃO das frames do Text e do Circle
// Outros elementos ao redor vão se ajustar ao ZStack maior!

// Efeito prático em HStack com alinhamento de base:
HStack(alignment: .bottom) {
    Text("A").padding().overlay(alignment: .topTrailing) {
        Text("badge")  // overlay não afeta alinhamento base
    }
    Text("B")  // alinha com a base do Text A
}

// Sem fixedSize — Text quebra linha em espaço pequeno:
Text("Este é um texto bem longo que pode quebrar linha")
    .frame(width: 100)
// Word wrapping em 100pts de largura

// Com fixedSize — Text usa tamanho ideal, pode sair dos bounds:
Text("Este é um texto bem longo que pode quebrar linha")
    .fixedSize()
    .frame(width: 100)  // text renderiza além de 100pts!

// Útil em HStack para garantir que Text não quebre:
HStack {
    Image(systemName: "calendar")
    Text("Seg, 31 de março de 2025")
        .fixedSize(horizontal: true, vertical: false)  // não quebra na horizontal
}

// Shape em ScrollView precisa de altura explícita:
ScrollView {
    Rectangle()
        .fill(.blue)
        .frame(height: 200)  // sem isso, Rectangle seria 10pts de altura
}

// maxWidth: .infinity — pelo menos tão largo quanto a proposta:
Text("Olá")
    .frame(maxWidth: .infinity)
    .background(.blue)
// Background azul ocupa toda a largura
// Se Text for maior que a proposta, frame também cresce

// minWidth: 0, maxWidth: .infinity — exatamente a proposta:
Text("Olá")
    .frame(minWidth: 0, maxWidth: .infinity)
    .background(.blue)
// Background azul ocupa exatamente a largura proposta
// Mesmo se Text for maior, frame respeita o máximo

// Padrão comum para botão full-width:
Button("Continuar") { continuar() }
    .buttonStyle(.borderedProminent)
    .frame(maxWidth: .infinity)  // ocupa toda a largura disponível
